                if (minDivisor[x] === x) {
                    minDivisor[x] = y;
                }
            }
        }
    }

    // Step 3: Calculate the total minimum sum
    let totalSum = 0;
    for (const num of nums) {
        // The final value for nums[i] is minDivisor[nums[i]]
        totalSum += minDivisor[num];
    }

