    const minDivisor: number[] = new Array(M_MAX + 1).fill(0);
    const present: boolean[] = new Array(M_MAX + 1).fill(false);

    // Step 1: Identify present numbers and initialize minDivisor
    for (const num of nums) {
        if (num > M_MAX || num < 1) continue; // Safety check, although constraints say they are within bounds
        present[num] = true;
        // Initial assumption: the minimum divisor is the number itself.
        minDivisor[num] = num; 
