    // Step 2: Sieve-like process to find the true minimum divisor for all present numbers
    // We iterate over all possible divisors y from 1 up to M_MAX.
    for (let y = 1; y <= M_MAX; y++) {
        // Only proceed if y is actually present in the original array U.
        if (!present[y]) {
            continue;
